// ΉΙεΉηΡΉΓ░(Ή┤ζΉηΡΉΓ░ - ΈΝΑΉ╢ε) Ά│ΕΉΓ░ ΉειΊΜ╕
// AssetSummaryΉζα assetCache_${userId} Ή║ΡΉΜε(5Έ╢Ε TTL)Έξ╝ Ά│╡ΉειΊΧεΈΜν.
// Ή║ΡΉΜεΆ░Α ΉΩΗΆ▒░ΈΓα ΈπΝΈμΝΈΡε Ά▓╜Ήγ░ FirestoreΉΩΡΉΕε ΉπΒΉιΣ ΈκεΈΥεΊΧεΈΜν.
import { db } from "../firebase";
import {
  doc,
  getDoc,
  collection,
  getDocs,
  query,
  where,
} from "firebase/firestore";
import { logger } from "./logger";

const CACHE_TTL = 5 * 60 * 1000;

function readAssetCache(userId) {
  try {
    const cached = localStorage.getItem(`assetCache_${userId}`);
    if (!cached) return null;
    const { data, ts } = JSON.parse(cached);
    if (Date.now() - ts >= CACHE_TTL) return null;
    return data;
  } catch {
    return null;
  }
}

/**
 * ΊΝΝΊΓ╣ΊΗ╡Ήηξ ΈΥ▒ ΉηΡΉΓ░ Έ│ΑΈΠβ ΉπΒΊδΕ, ΉΙεΉηΡΉΓ░ΉζΕ 5Έ╢Ε TTL Ή║ΡΉΜεΈκε ΊΣεΉΜεΊΧαΈΛΦ ΊβΦΈσ┤ΈΥνΉζ┤ Ήαδ Ά░ΤΉζΕ Ά│ΕΉΗΞ
 * Έ│┤ΉΩυΉμ╝ΉπΑ ΉΧΛΈΠΕΈκζ Ά┤ΑΈιρ localStorage Ή║ΡΉΜεΈξ╝ ΈςρΈΣΡ Έυ┤ΊγρΊβΦΊΧεΈΜν. ΈΜνΉζΝ ΉπΕΉηΖ/ΊΠ┤ΈπΒ ΉΜε fresh ΈκεΈΥε.
 * - assetCache_{uid}: netAssets/FinancialRestrictionBanner Ά│╡Ήει Ή║ΡΉΜε
 * - firestore_cache_myAssets_{uid}: MyAssets "Ή┤ζ ΉΙεΉηΡΉΓ░" Ή║ΡΉΜε(+ ΈιΙΆ▒░ΉΜε ΈΞΦΈ╕Φ suffix)
 * ΉηΖΆ╕ΙΉζΑ cashέΗΦparking ΉΔΒΉΘΕΈζ╝ ΉΜνΉιε ΉΙεΉηΡΉΓ░ΉζΑ Έ╢ΙΈ│ΑΉζ╕ΈΞ░, cashΈπΝ ΉΜνΉΜεΆ░ΕΉζ┤Ά│ι parkingΉζ┤ Ή║ΡΉΜεΈζ╝
 * ΉηΖΆ╕Ι ΉπΒΊδΕ ΉΙεΉηΡΉΓ░Ήζ┤ ΉηΖΆ╕ΙΉΧκΈπΝΊΒ╝ ΉηιΆ╣Ρ ΈΓχΆ▓Ν Έ│┤Ήζ┤ΈΞα Έ▓ΕΆ╖╕Έξ╝ Ή░ρΈΜρΊΧεΈΜν.
 */
export function invalidateAssetCaches(userId) {
  if (!userId) return;
  try {
    localStorage.removeItem(`assetCache_${userId}`);
    localStorage.removeItem(`firestore_cache_myAssets_${userId}`);
    localStorage.removeItem(`firestore_cache_myAssets_${userId}_${userId}`);
  } catch {
    /* localStorage ΉιΣΆ╖╝ ΉΜνΊΝρ Έυ┤ΉΜε */
  }
}

async function loadAssetDataFromDb(userId, userName, classCode) {
  const promises = [];

  promises.push(
    getDoc(doc(db, "users", userId, "financials", "parkingAccount"))
      .then((snap) => (snap.exists() ? snap.data().balance || 0 : 0))
      .catch(() => 0),
  );

  // ΉαΙΆ╕Ι/ΉιΒΆ╕Ι/ΈΝΑΉ╢εΉζΑ ΈςρΈΣΡ users/{uid}/products Ή╗υΈιΚΉΖα(type=deposit|savings|loan)Ήζ┤ ΉιΧΉΜζ
  // ΉΗΝΉΛνΈΜν(ParkingAccountΆ░Α ΉΔζΉΕ▒/ΉΔΒΊβα, ΉηΡΈΠβΉΔΒΊβα ΊδΖΈΠΕ Ήζ┤ Ά▓╜Έκε ΉΓυΉγσ). Ά│╝Ά▒░ financials/loans
  // Έυ╕ΉΕεΈΛΦ writeΆ░Α ΉΓυΈζ╝ΉπΕ Ήμ╜ΉζΑ Ά▓╜ΈκεΈζ╝ ΊΧφΉΔΒ Έ╣ΕΉΨ┤, ΈΝΑΉ╢εΉζ┤ 0Ήε╝Έκε ΉηκΊαΑ ΉΙεΉηΡΉΓ░Ήζ┤ Ά│╝ΈΝΑ(Έ╢ΑΉ▒Ε Έψ╕Ή░ρΆ░Ρ)
  // ΊΣεΉΜεΈΡαΈΞα Έ▓ΕΆ╖╕Έξ╝ Ή░ρΈΜρΊΧεΈΜν. ΊΧε Έ▓ΙΉζα Ήζ╜Ά╕░Έκε ΉΕ╕ ΉλΖΈξαΈξ╝ ΊΧρΆ╗α Έ╢ΕΈξαΊΧεΈΜν.
  promises.push(
    getDocs(collection(db, "users", userId, "products"))
      .then((snap) => {
        const deposits = [];
        const savings = [];
        const loans = [];
        snap.docs.forEach((d) => {
          const p = d.data();
          if (p.type === "deposit") deposits.push(p);
          else if (p.type === "savings") savings.push(p);
          else if (p.type === "loan") loans.push(p);
        });
        return { deposits, savings, loans };
      })
      .catch(() => ({ deposits: [], savings: [], loans: [] })),
  );

  // Έ╢ΑΈΠβΉΓ░: realEstateProperties.owner ΊΧΕΈΥεΈΛΦ ΉΗΝΉειΉηΡ UID(=userId)Έκε ΉιΑΉηξΈΡεΈΜν(ΉΕεΈ▓Ε Ά▒░Έηα/ΈΥ▒Έκζ
  // ΈκεΉπΒ Ά╕░ΉνΑ). Ά│╝Ά▒░ owner==userName(Ήζ┤ΈοΕ) Ή┐╝ΈουΈΛΦ ΊΧφΉΔΒ Έ╣Ι Ά▓░Ά│╝Έζ╝ Έ╢ΑΈΠβΉΓ░Ήζ┤ ΉΙεΉηΡΉΓ░ΉΩΡΉΕε ΈΙΕΈζ╜ΈΡΡΈΜν.
  if (classCode && userId) {
    promises.push(
      getDocs(
        query(
          collection(db, "classes", classCode, "realEstateProperties"),
          where("owner", "==", userId),
        ),
      )
        .then((snap) => snap.docs.map((d) => ({ id: d.id, ...d.data() })))
        .catch(() => []),
    );
  } else {
    promises.push(Promise.resolve([]));
  }

  promises.push(
    getDocs(collection(db, "users", userId, "portfolio"))
      .then((snap) => {
        const holdings = [];
        snap.docs.forEach((d) => {
          const data = d.data();
          if (data.quantity > 0) {
            holdings.push({ stockId: parseInt(d.id) || d.id, ...data });
          }
        });
        return { holdings };
      })
      .catch(() => ({ holdings: [] })),
  );

  // Ήμ╝ΉΜζ ΉΜεΉΕ╕: ΉιΕΉΩφ Έψ╕Έθυ Έυ╕ΉΕε 1Ά░εΈπΝ Ήζ╜ΉζΝ(Ήζ╜Ά╕░ Έ╣ΕΉγσ Ή╡εΉΗΝ).
  // ΉιΧΉΜζ ΉΗΝΉΛνΈΛΦ CentralStocks Ή╗υΈιΚΉΖαΉζ┤Ά│ι Settings/centralStocksCacheΈΛΦ realStockServiceΆ░Α
  // Ά░▒ΉΜιΊΧαΈΛΦ ΉΓ┤ΉΧΕΉηΙΈΛΦ ΉΛνΈΔΖΉΔ╖Ήζ┤ΈΜν. Ά│╝Ά▒░ classes/{classCode}/stocks/stockList Ά▓╜ΈκεΈΛΦ writeΆ░Α
  // ΉΓυΈζ╝ΉπΕ Ήμ╜ΉζΑ Ά▓╜ΈκεΈζ╝ ΊΧφΉΔΒ Έ╣ΕΉΨ┤, Ήμ╝ΉΜζΉζ┤ ΉΙεΉηΡΉΓ░ΉΩΡΉΕε ΊΗ╡Ήπ╕Έκε ΈΙΕΈζ╜ΈΡαΈΞα Έ▓ΕΆ╖╕Έξ╝ Ή░ρΈΜρΊΧεΈΜν.
  promises.push(
    getDoc(doc(db, "Settings", "centralStocksCache"))
      .then((snap) => {
        if (!snap.exists()) return [];
        const d = snap.data();
        return Array.isArray(d.stocks) ? d.stocks : [];
      })
      .catch(() => []),
  );

  const [parking, products, realEstate, portfolio, stocks] =
    await Promise.all(promises);

  const data = {
    parking,
    deposits: products.deposits,
    savings: products.savings,
    loans: products.loans,
    realEstate,
    portfolio,
    stocks,
  };

  // ΏθΦξ [Έ╣ΕΉγσ Ή╡εΉιΒΊβΦ] AssetSummaryΉβΑ Ά│╡ΉειΊΧαΈΛΦ 5Έ╢Ε Ή║ΡΉΜεΉΩΡ ΉπΒΉιΣ Ά╕░Έκζ.
  // Ά╕░Ήκ┤ΉΩΦ readAssetCacheΈκε "Ήζ╜Ά╕░ΈπΝ" ΊΧαΆ│ι ΉΥ░ΉπΑ ΉΧΛΉΧΕ, ΉηΡΉΓ░ ΊΟαΉζ┤ΉπΑ(AssetSummary)Ά░Α ΉΧΕΈΜΝ
  // ΊβΦΈσ┤ΉΩΡΉΕεΈΛΦ Ή║ΡΉΜεΆ░Α ΉαΒΉδΡΊηΙ Έ╣ΕΉΨ┤ Έπν Ία╕Ή╢ε(ΊΛ╣ΊηΙ FinancialRestrictionBanner 60Ή┤Ι ΊΠ┤ΈπΒ)ΈπΙΈΜν
  // ΊΤΑΈκεΈΥε(5Έυ╕ΉΕε)Ά░Α Έ░εΉΔζΊΨΙΈΜν. Ήζ┤Ήιε ΉΨ┤ΈΦΦΉΕε Ία╕Ή╢εΊΧαΈΥι 5Έ╢ΕΆ░Ε Ή║ΡΉΜε ΉηυΉΓυΉγσ έΗΤ Ήζ╜Ά╕░ Ά╕ΚΆ░Ρ.
  try {
    localStorage.setItem(
      `assetCache_${userId}`,
      JSON.stringify({ data, ts: Date.now() }),
    );
  } catch {
    /* ΉιΑΉηξ ΉΜνΊΝρ Έυ┤ΉΜε */
  }

  return data;
}

function computeNetAssets({
  cash = 0,
  coupons = 0,
  couponValue = 1000,
  data,
}) {
  const parking = data?.parking || 0;
  const deposits = Array.isArray(data?.deposits) ? data.deposits : [];
  const savings = Array.isArray(data?.savings) ? data.savings : [];
  const loans = Array.isArray(data?.loans) ? data.loans : [];
  const realEstate = Array.isArray(data?.realEstate) ? data.realEstate : [];
  const portfolio = data?.portfolio || { holdings: [] };
  const stocks = Array.isArray(data?.stocks) ? data.stocks : [];

  const couponValueTotal = coupons * couponValue;
  const depositSavingsTotal = [...deposits, ...savings].reduce(
    (sum, p) => sum + (Number(p.balance) || 0),
    0,
  );
  const realEstateValue = realEstate.reduce(
    (sum, a) => sum + (Number(a.price) || Number(a.value) || 0),
    0,
  );
  const stockValue = (portfolio.holdings || []).reduce((sum, h) => {
    // Ήμ╝ΉΜζ ΈπνΉ╣φΉζΑ Έυ╕ΉηΡΉΩ┤ Ά╕░ΉνΑΉε╝Έκε ΊΗ╡Ήζ╝(portfolio docIdΆ░Α ΉΙτΉηΡΊαΧΉζ┤ΉΨ┤ΈΠΕ ΊΔΑΉηΖ Έψ╕ΉΛνΈπνΉ╣α Έ░σΉπΑ).
    const info = stocks.find((s) => String(s.id) === String(h.stockId));
    if (info && info.isListed && h.quantity > 0) {
      return sum + (Number(info.price) || 0) * h.quantity;
    }
    return sum;
  }, 0);
  const loanBalance = loans.reduce(
    (sum, l) =>
      sum + (Number(l.remainingPrincipal) || Number(l.balance) || 0),
    0,
  );
  return (
    (Number(cash) || 0) +
    couponValueTotal +
    parking +
    depositSavingsTotal +
    stockValue +
    realEstateValue -
    loanBalance
  );
}

function sumLoanBalance(loans) {
  return (Array.isArray(loans) ? loans : []).reduce(
    (sum, l) => sum + (Number(l.remainingPrincipal) || Number(l.balance) || 0),
    0,
  );
}

/**
 * ΉΙεΉηΡΉΓ░ + ΈΝΑΉ╢ε ΊΧσΆ│ΕΈξ╝ ΊΧε Έ▓ΙΉζα (Ή║ΡΉΜε Ήγ░ΉΕι) ΈκεΈΥεΈκε ΊΧρΆ╗α Έ░αΊβαΊΧεΈΜν.
 * FinancialRestrictionBannerΆ░Α netΆ│╝ loanΉζΕ ΈΣα ΈΜν ΊΧΕΉγΦΈκε ΊΧαΈψΑΈκε, loans Έυ╕ΉΕεΈξ╝
 * Έ│ΕΈΠΕΈκε ΈαΡ Ήζ╜ΉπΑ ΉΧΛΈΠΕΈκζ ΈΠβΉζ╝ ΈΞ░Ήζ┤ΊΕ░ΉΩΡΉΕε ΊΧρΆ╗α Ά│ΕΉΓ░ΊΧεΈΜν.
 * @returns {Promise<{net:number, loanTotal:number}>}
 */
export async function getNetAssetsDetail(user, couponValue = 1000) {
  if (!user || !user.id) return { net: 0, loanTotal: 0 };
  const cash = Number(user.cash) || 0;
  const coupons = Number(user.coupons) || 0;

  let data = readAssetCache(user.id);
  if (!data) {
    try {
      data = await loadAssetDataFromDb(user.id, user.name, user.classCode);
    } catch (e) {
      logger.error("[netAssets] ΈκεΈΥε ΉΜνΊΝρ:", e);
      data = null;
    }
  }
  const net = computeNetAssets({ cash, coupons, couponValue, data });
  const loanTotal = sumLoanBalance(data?.loans);
  return { net, loanTotal };
}

/**
 * ΉΓυΉγσΉηΡΉζα ΉΙεΉηΡΉΓ░ΉζΕ Ά│ΕΉΓ░ΊΧεΈΜν. Ή║ΡΉΜε Ήγ░ΉΕι, ΉΩΗΉε╝Έσ┤ Firestore ΈκεΈΥε.
 * @returns {Promise<number>} ΉΙεΉηΡΉΓ░ (ΉζΝΉΙα Ά░ΑΈΛξ)
 */
export async function getNetAssets(user, couponValue = 1000) {
  return (await getNetAssetsDetail(user, couponValue)).net;
}

/**
 * ΉΙεΉηΡΉΓ░Ήζ┤ ΈπΙΉζ┤ΈΕΙΉΛνΉζ╕ΉπΑ ΊβΧΉζ╕ (ΉΜνΊΝρ ΉΜε false Έ░αΊβα έΑΦ Ά│╝ΈΠΕΊΧε Ή░ρΈΜρ Έ░σΉπΑ)
 */
export async function isNetAssetsNegative(user, couponValue = 1000) {
  try {
    const net = await getNetAssets(user, couponValue);
    return net < 0;
  } catch (e) {
    logger.error("[netAssets] ΊΝΡΉιΧ ΉΜνΊΝρ:", e);
    return false;
  }
}

export const NEGATIVE_ASSETS_MESSAGE =
  "ΉΙεΉηΡΉΓ░Ήζ┤ ΈπΙΉζ┤ΈΕΙΉΛνΉηΖΈΜΙΈΜν. ΈΝΑΉ╢ε ΉΔΒΊβα┬╖ΉηΡΉΓ░ ΈπνΈΠΕ┬╖Ά│╝Ήιε Έ│┤ΉΔΒ ΈΥ▒Ήε╝Έκε ΉηΡΉΓ░ΉζΕ ΊγΝΈ│╡ΊΧε ΊδΕ Ήζ┤ΉγσΊΧ┤Ήμ╝ΉΕ╕ΉγΦ.";
