// src/pages/market/GroupPurchase.js
// ΊΧρΆ╗αΆ╡υΈπν - ΊΧβΆ╕Κ Ή╣εΆ╡υΈΥνΆ│╝ ΊΧρΆ╗α ΈςρΆ╕ΙΊΧαΉΩυ ΉΧΕΉζ┤ΊΖεΉζΕ Ά╡υΈπνΊΧαΈΛΦ Ά╕░ΈΛξ
import React, { useState, useEffect, useCallback, useMemo } from "react";
import { useAuth } from "../../contexts/AuthContext";
import { useItems } from "../../contexts/ItemContext";
import { useCurrency } from "../../contexts/CurrencyContext";
import {
  db,
  doc,
  collection,
  addDoc,
  updateDoc,
  deleteDoc,
  getDoc,
  getDocs,
  query,
  where,
  orderBy,
  serverTimestamp,
  runTransaction,
  Timestamp,
  functions,
  increment,
} from "../../firebase";
import { httpsCallable } from "firebase/functions";
import { addItemToInventory } from "../../firebase/firebaseDb";
import {
  Users,
  Plus,
  HandCoins,
  Trophy,
  Clock,
  X,
  ChevronDown,
  ChevronUp,
  Trash2,
  AlertCircle,
} from "lucide-react";
import { formatKoreanNumber } from "../../utils/numberFormatter";
import {
  isNetAssetsNegative,
  NEGATIVE_ASSETS_MESSAGE,
} from "../../utils/netAssets";
import { logger } from "../../utils/logger";

export default function GroupPurchase() {
  const { user, userDoc, isAdmin, optimisticUpdate } = useAuth();
  const { items } = useItems() || { items: [] };
  const { currencyUnit } = useCurrency?.() || { currencyUnit: "ΉΧΝΉ░υ" };
  const classCode = userDoc?.classCode;

  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [contributeModal, setContributeModal] = useState(null);
  const [contributeAmount, setContributeAmount] = useState("");
  // Ώθγρ ΉνΣΈ│╡ Ά▓░Ήιε Έ░σΉπΑ lock
  const [isContributing, setIsContributing] = useState(false);
  const [expandedId, setExpandedId] = useState(null);
  const [filter, setFilter] = useState("active"); // active, completed, all

  // ΉΔΙ Ή║ιΊΟαΉζ╕ ΊΠ╝
  const [newCampaign, setNewCampaign] = useState({
    itemName: "",
    itemIcon: "ΏθΟΒ",
    itemDescription: "",
    targetPrice: "",
    useStoreItem: false,
    selectedItemId: "",
  });

  // Ή║ιΊΟαΉζ╕ ΈςσΈκζ ΈκεΈΥε
  const fetchCampaigns = useCallback(async () => {
    if (!classCode) return;
    try {
      const q = query(
        collection(db, "groupPurchases"),
        where("classCode", "==", classCode),
        orderBy("createdAt", "desc"),
      );
      const snap = await getDocs(q);
      const list = snap.docs.map((d) => ({ id: d.id, ...d.data() }));
      setCampaigns(list);
    } catch (err) {
      logger.error("ΊΧρΆ╗αΆ╡υΈπν ΈκεΈΥε ΉΜνΊΝρ:", err);
    } finally {
      setLoading(false);
    }
  }, [classCode]);

  useEffect(() => {
    fetchCampaigns();
  }, [fetchCampaigns]);

  // ΏθΦξ Ή║ιΊΟαΉζ╕Ήζα targetPriceΈξ╝ ΉΔΒΉιΡ ΊαΕΉηυΆ░ΑΈκε ΉΜνΉΜεΆ░Ε ΈΠβΆ╕░ΊβΦ
  // ΉΔΒΉιΡ Ά░ΑΆ▓σ Ήζ╕ΉΔΒ/Ήζ╕ΊΧα ΉΜε ΊΧρΆ╗αΆ╡υΈπνΈΠΕ ΉηΡΈΠβΉε╝Έκε ΈΦ░Έζ╝Ά░Ρ
  const enrichedCampaigns = useMemo(() => {
    if (!items || items.length === 0) return campaigns;
    return campaigns.map((c) => {
      if (!c.selectedItemId) return c;
      const storeItem = items.find((i) => i.id === c.selectedItemId);
      const currentShopPrice = Number(storeItem?.price) || 0;
      if (currentShopPrice <= 0) return c;
      // ΉΔΒΉιΡ Ά░ΑΆ▓σΉζ┤ ΉιΑΉηξΈΡε targetPriceΉβΑ ΈΜνΈξ┤Έσ┤ override
      if (currentShopPrice !== Number(c.targetPrice)) {
        return { ...c, targetPrice: currentShopPrice, _priceOverride: true };
      }
      return c;
    });
  }, [campaigns, items]);

  // Ή║ιΊΟαΉζ╕ ΉΔζΉΕ▒
  const handleCreate = async () => {
    if (!newCampaign.selectedItemId) {
      alert("ΉΧΕΉζ┤ΊΖεΉζΕ Έρ╝ΉιΑ ΉΕιΊΔζΊΧ┤Ήμ╝ΉΕ╕ΉγΦ.");
      return;
    }

    // ΏθΦξ ΉΔΒΉιΡ ΉΧΕΉζ┤ΊΖεΉζα ΊαΕΉηυ Ά░ΑΆ▓σ Ά░ΧΉιε ΉΓυΉγσ + Ά░βΉζΑ ΉΧΕΉζ┤ΊΖεΉΩΡ ΈΝΑΊΧ┤ 1Ά▒┤ΈπΝ ΊΩΙΉγσ
    let currentShopPrice = 0;
    try {
      const storeItemRef = doc(db, "storeItems", newCampaign.selectedItemId);
      const storeItemSnap = await getDoc(storeItemRef);
      if (!storeItemSnap.exists()) {
        alert("ΉΔΒΉιΡΉΩΡΉΕε ΉΧΕΉζ┤ΊΖεΉζΕ Ή░╛ΉζΕ ΉΙα ΉΩΗΉΛ╡ΈΜΙΈΜν.");
        return;
      }
      const storeData = storeItemSnap.data();
      currentShopPrice = Number(storeData.price) || 0;
      if (currentShopPrice <= 0) {
        alert("ΉειΊγρΊΧε Ά░ΑΆ▓σΉζ┤ ΉΩΗΈΛΦ ΉΧΕΉζ┤ΊΖεΉηΖΈΜΙΈΜν.");
        return;
      }

      // ΊΧ┤ΈΜ╣ ΉΧΕΉζ┤ΊΖεΉΩΡ ΈΝΑΊΧ┤ Ήζ┤Έψ╕ ΉπΕΊΨΚ ΉνΣΉζ╕ Ή║ιΊΟαΉζ╕Ήζ┤ ΉηΙΉε╝Έσ┤ Ή░ρΈΜρ (ΊΧβΆ╕Κ ΈΓ┤)
      const dupQuery = query(
        collection(db, "groupPurchases"),
        where("selectedItemId", "==", newCampaign.selectedItemId),
        where("classCode", "==", classCode),
        where("status", "==", "active"),
      );
      const dupSnap = await getDocs(dupQuery);
      if (!dupSnap.empty) {
        alert(
          "Ήζ┤Έψ╕ Ά░βΉζΑ ΉΧΕΉζ┤ΊΖεΉζα ΊΧρΆ╗αΆ╡υΈπνΆ░Α ΉπΕΊΨΚ ΉνΣΉηΖΈΜΙΈΜν. ΉβΕΈμΝΈΡαΆ▒░ΈΓα Ή╖ρΉΗΝΈΡε ΊδΕΉΩΡ ΉΔΙΈκε ΈπΝΈΥν ΉΙα ΉηΙΉΛ╡ΈΜΙΈΜν.\n(ΊΧε Έ▓ΙΉΩΡ ΊΧε Ά▒┤ΈπΝ ΊΩΙΉγσΈΡρ)",
        );
        return;
      }
    } catch (err) {
      logger.error("Ή║ιΊΟαΉζ╕ ΉΓυΉιΕ Ή▓┤ΊΒυ ΉΜνΊΝρ:", err);
      alert("Ή║ιΊΟαΉζ╕ ΉΔζΉΕ▒ ΉιΕ ΊβΧΉζ╕ΉΩΡ ΉΜνΊΝρΊΨΙΉΛ╡ΈΜΙΈΜν.");
      return;
    }

    try {
      await addDoc(collection(db, "groupPurchases"), {
        classCode,
        itemName: newCampaign.itemName.trim(),
        itemIcon: newCampaign.itemIcon || "ΏθΟΒ",
        itemDescription: newCampaign.itemDescription.trim(),
        selectedItemId: newCampaign.selectedItemId || null,
        // ΏθΦξ ΈςσΊΣε Ά░ΑΆ▓σΉζΑ ΉΔΒΉιΡ ΊαΕΉηυ Ά░ΑΆ▓σΉε╝Έκε Ά░ΧΉιε Ά│ιΉιΧ (ΉΓυΉγσΉηΡ ΉηΖΈιξ Έυ┤ΉΜε)
        targetPrice: currentShopPrice,
        currentAmount: 0,
        initiatorId: user.uid,
        initiatorName: userDoc?.name || "ΉΧΝ ΉΙα ΉΩΗΉζΝ",
        contributors: [],
        status: "active",
        createdAt: serverTimestamp(),
        completedAt: null,
        winnerId: null,
        winnerName: null,
      });
      setShowCreateModal(false);
      setNewCampaign({
        itemName: "",
        itemIcon: "ΏθΟΒ",
        itemDescription: "",
        targetPrice: "",
        useStoreItem: false,
        selectedItemId: "",
      });
      fetchCampaigns();
    } catch (err) {
      logger.error("ΊΧρΆ╗αΆ╡υΈπν ΉΔζΉΕ▒ ΉΜνΊΝρ:", err);
      alert("ΉΔζΉΕ▒ΉΩΡ ΉΜνΊΝρΊΨΙΉΛ╡ΈΜΙΈΜν.");
    }
  };

  // Ά╕░ΉΩυ(ΈςρΆ╕Ι Ή░╕ΉΩυ)
  const handleContribute = async () => {
    // Ώθγρ ΉνΣΈ│╡ Ά▓░Ήιε Έ░σΉπΑ έΑΦ Ήζ┤Έψ╕ Ή▓αΈου ΉνΣΉζ┤Έσ┤ Έυ┤ΉΜε
    if (isContributing) {
      logger.warn?.("[GroupPurchase] handleContribute ΉνΣΈ│╡ Ία╕Ή╢ε Ή░ρΈΜρ");
      return;
    }
    setIsContributing(true);

    const amount = parseInt(contributeAmount);
    if (!amount || amount <= 0 || !contributeModal) {
      setIsContributing(false);
      return;
    }

    const campaign = contributeModal;
    const remaining = campaign.targetPrice - campaign.currentAmount;
    const actualAmount = Math.min(amount, remaining);

    if ((userDoc?.cash || 0) < actualAmount) {
      setIsContributing(false);
      alert("ΉηΦΉΧκΉζ┤ Έ╢ΑΉκ▒ΊΧσΈΜΙΈΜν.");
      return;
    }

    // ΉΙεΉηΡΉΓ░(ΉηΡΉΓ░-ΈΝΑΉ╢εΈψ╕ΉΔΒΊβαΆ╕Ι) ΈπΙΉζ┤ΈΕΙΉΛνΈσ┤ Ή░╕ΉΩυ Ά╕ΙΉπΑ
    if (await isNetAssetsNegative(userDoc)) {
      setIsContributing(false);
      alert(NEGATIVE_ASSETS_MESSAGE);
      return;
    }

    // ΏθΦξ ΈΓβΆ┤ΑΉιΒ ΉΩΖΈΞ░Ήζ┤ΊΛ╕: ΉοΚΉΜε ΊαΕΆ╕Ι Ή░ρΆ░Ρ ΊΣεΉΜε
    const finalAmount = actualAmount;
    if (optimisticUpdate) {
      optimisticUpdate({ cash: -finalAmount });
    }

    let transactionCommitted = false;
    try {
      const campaignRef = doc(db, "groupPurchases", campaign.id);
      const userRef = doc(db, "users", user.uid);

      const result = await runTransaction(db, async (transaction) => {
        const campaignSnap = await transaction.get(campaignRef);
        const userSnap = await transaction.get(userRef);

        // ΏθΦξ ΉΔΒΉιΡ ΊαΕΉηυΆ░Α ΉΜνΉΜεΆ░Ε ΈΠβΆ╕░ΊβΦ έΑΦ targetPriceΈξ╝ storeItemsΉζα Ή╡εΉΜι Ά░ΑΆ▓σΉε╝Έκε
        let storeItemSnap = null;
        const campaignData = campaignSnap.data();
        if (campaignData?.selectedItemId) {
          const storeItemRef = doc(db, "storeItems", campaignData.selectedItemId);
          storeItemSnap = await transaction.get(storeItemRef);
        }

        if (!campaignSnap.exists() || !userSnap.exists()) {
          throw new Error("Έυ╕ΉΕεΈξ╝ Ή░╛ΉζΕ ΉΙα ΉΩΗΉΛ╡ΈΜΙΈΜν.");
        }

        const cData = campaignSnap.data();
        const uData = userSnap.data();

        if (cData.status !== "active") {
          throw new Error("Ήζ┤Έψ╕ ΉβΕΈμΝΈΡε Ή║ιΊΟαΉζ╕ΉηΖΈΜΙΈΜν.");
        }

        // ΉΔΒΉιΡ ΊαΕΉηυΆ░ΑΈκε targetPrice override (Ά░ΑΆ▓σ Έ│ΑΈΠβ Έ░αΉαΒ)
        const currentShopPrice = Number(storeItemSnap?.data()?.price) || 0;
        const effectiveTargetPrice =
          currentShopPrice > 0 ? currentShopPrice : Number(cData.targetPrice);

        const currentRemaining = effectiveTargetPrice - cData.currentAmount;
        const txFinalAmount = Math.min(actualAmount, currentRemaining);

        // Ή║ιΊΟαΉζ╕ docΉζα targetPriceΈΠΕ ΈΠβΆ╕░ΊβΦ (ΈΜνΉζΝ Ήκ░ΊγΝ ΉΜε Ήζ╝Ά┤ΑΉΕ▒)
        if (currentShopPrice > 0 && currentShopPrice !== Number(cData.targetPrice)) {
          cData.targetPrice = effectiveTargetPrice;
        }

        if (uData.cash < txFinalAmount) {
          throw new Error("ΉηΦΉΧκΉζ┤ Έ╢ΑΉκ▒ΊΧσΈΜΙΈΜν.");
        }

        const newContributors = [...(cData.contributors || [])];
        const existingIdx = newContributors.findIndex(
          (c) => c.userId === user.uid,
        );
        if (existingIdx >= 0) {
          newContributors[existingIdx].amount += txFinalAmount;
          newContributors[existingIdx].lastContributedAt = new Date();
          // firstContributedAtΉζΑ ΉειΉπΑ (ΉΩΗΉε╝Έσ┤ Ά╕░Ήκ┤ contributedAt ΉΓυΉγσ)
          if (!newContributors[existingIdx].firstContributedAt) {
            newContributors[existingIdx].firstContributedAt =
              newContributors[existingIdx].contributedAt || new Date();
          }
        } else {
          const now = new Date();
          newContributors.push({
            userId: user.uid,
            userName: userDoc?.name || "ΉΧΝ ΉΙα ΉΩΗΉζΝ",
            amount: txFinalAmount,
            contributedAt: now,
            firstContributedAt: now,
            lastContributedAt: now,
          });
        }

        const newTotal = cData.currentAmount + txFinalAmount;
        const isCompleted = newTotal >= cData.targetPrice;

        // Ή╡εΈΜν Ά╕░ΉΩυΉηΡ Ά│ΕΉΓ░ (ΈΠβΈξι ΉΜε Έρ╝ΉιΑ Ή░╕ΉΩυΊΧε ΉΓυΈηΝ Ήγ░ΉΕι)
        let winnerId = null;
        let winnerName = null;
        if (isCompleted) {
          const getTime = (c) => {
            const t = c.firstContributedAt || c.contributedAt;
            return t?.toMillis?.() || t?.getTime?.() || 0;
          };
          const topContributor = [...newContributors].sort((a, b) => {
            if (b.amount !== a.amount) return b.amount - a.amount;
            return getTime(a) - getTime(b); // Έρ╝ΉιΑ Ή░╕ΉΩυΊΧε ΉΓυΈηΝ Ήγ░ΉΕι
          })[0];
          winnerId = topContributor?.userId || null;
          winnerName = topContributor?.userName || null;
        }

        transaction.update(campaignRef, {
          currentAmount: newTotal,
          contributors: newContributors,
          status: isCompleted ? "completed" : "active",
          completedAt: isCompleted ? new Date() : null,
          winnerId,
          winnerName,
          // Ή║ιΊΟαΉζ╕ docΉζα targetPriceΈξ╝ ΉΔΒΉιΡ ΊαΕΉηυΆ░ΑΈκε ΈΠβΆ╕░ΊβΦ (ΈΜνΉζΝ Ήκ░ΊγΝ Ήζ╝Ά┤ΑΉΕ▒)
          targetPrice: effectiveTargetPrice,
        });

        // ΉιΙΈΝΑΆ░Τ ΈΞχΉΨ┤ΉΥ░Ά╕░ Ά╕ΙΉπΑ έΑΦ increment ΉΓυΉγσΉε╝Έκε race condition Έ░σΉπΑ
        transaction.update(userRef, {
          cash: increment(-txFinalAmount),
        });

        // Ά╕░ΉΩυΉηΡ Έ│╕Ήζ╕ ΊβεΈΠβ ΈκεΆ╖╕ (cash Ή░ρΆ░Ρ ΊζΦΉιΒ)
        const logRef = doc(collection(db, "activity_logs"));
        const expireAt = new Date();
        expireAt.setDate(expireAt.getDate() + 90);
        transaction.set(logRef, {
          userId: user.uid,
          userName: userDoc?.name || "ΉΧΝ ΉΙα ΉΩΗΉζΝ",
          classCode,
          type: "ΊαΕΆ╕Ι Ή╢εΆ╕Ι",
          description: `ΊΧρΆ╗αΆ╡υΈπν Ή░╕ΉΩυ: ${cData.itemName} (-${txFinalAmount.toLocaleString()}ΉδΡ)`,
          amount: -txFinalAmount,
          metadata: {
            campaignId: campaign.id,
            itemName: cData.itemName,
            isCompleted,
          },
          timestamp: serverTimestamp(),
          expireAt: Timestamp.fromDate(expireAt),
        });

        // ΊΛ╕ΈηεΉηφΉΖα Έ░ΨΉΩΡΉΕε ΉΧΕΉζ┤ΊΖε ΉπΑΆ╕ΚΉζΕ ΉεΕΊΧε ΈΞ░Ήζ┤ΊΕ░ Έ░αΊβα
        return { isCompleted, winnerId, winnerName, cData, txFinalAmount };
      });

      // ΊΛ╕ΈηεΉηφΉΖα Ή╗νΈ░Μ ΉΕ▒Ά│╡ - Ήζ┤ΊδΕ ΉΩΡΈθυΈΛΦ cash ΈκνΈ░▒ ΈΝΑΉΔΒΉζ┤ ΉΧΕΈΜα
      transactionCommitted = true;

      // ΈςσΊΣε ΈΜυΉΕ▒ ΉΜε: ΉΕεΈ▓ΕΉΓυΉζ┤ΈΥε Cloud FunctionΉε╝Έκε ΉεΕΉηΕ
      //   - ΉΧΕΉζ┤ΊΖε ΉπΑΆ╕Κ (ΉΕεΈ▓Ε Ά╢ΝΊΧε)
      //   - storeItems ΉηυΆ│ι/Ά░ΑΆ▓σ Ά░▒ΉΜι (admin SDK)
      //   - Ά┤ΑΈουΉηΡ cash ΉηΖΆ╕Ι + ΉηυΆ│ιΈ│┤Ή╢σΈ╣Ε Ή░ρΆ░Ρ
      //   - VAT Ά╕░Έκζ, activity_logs (winner + admin)
      if (result?.isCompleted) {
        try {
          const completeFn = httpsCallable(functions, "completeGroupPurchase");
          const cfResult = await completeFn({ campaignId: campaign.id });
          if (cfResult?.data?.alreadyAwarded) {
            // Ήζ┤Έψ╕ Ή▓αΈουΈΡρ - ΉΧΝΈο╝ ΉΔζΈη╡
          } else {
            alert(
              `ΏθΟΚ ΈςσΊΣε ΈΜυΉΕ▒! ${result.winnerName}ΈΜαΉζ┤ Ή╡εΈΜν Ά╕░ΉΩυΉηΡΈκε '${result.cData.itemName}'ΉζΕ(Έξ╝) ΊγΞΈΥζΊΨΙΉΛ╡ΈΜΙΈΜν!`,
            );
          }
        } catch (cfErr) {
          logger.error("ΊΧρΆ╗αΆ╡υΈπν ΉβΕΈμΝ Ή▓αΈου(CF) ΉΜνΊΝρ:", cfErr);
          // ΊΠ┤Έ░▒: Ήζ╕Έ▓νΊΗιΈουΈπΝΉζ┤Έζ╝ΈΠΕ ΊΒ┤Έζ╝Ήζ┤ΉΨ╕ΊΛ╕ΉΩΡΉΕε ΉΜεΈΠΕ (ΉηυΆ│ι/Ά░ΑΆ▓σ Ά░▒ΉΜιΉζΑ ΊΠυΆ╕░)
          try {
            let fallbackItemId = result.cData?.selectedItemId;
            if (!fallbackItemId && result.cData?.itemName && items?.length > 0) {
              const matched = items.find((i) => i.name === result.cData.itemName);
              if (matched) fallbackItemId = matched.id;
            }
            if (fallbackItemId && result.winnerId) {
              // ΏθΟ░ randomDrawΈσ┤ type+Ή╢ΦΉ▓ρ ΈσΦΊΔΑΆ╣ΝΉπΑ ΈΕαΆ▓ρ ΉΜνΉιε ΈΠΝΈο╝ΊΝΡΉε╝Έκε Έ│┤Ήζ┤Ά▓Ν (ΉΩΗΉε╝Έσ┤ Ήζ╝Έ░αΊΖε 5Έ╢Ε Ή╖ρΆ╕Κ)
              const storeMeta =
                items?.find((i) => i.id === fallbackItemId) || {};
              const fallbackDetails = {
                name: result.cData.itemName,
                icon: result.cData.itemIcon || "ΏθΟΒ",
                type: storeMeta.type || "item",
              };
              if (storeMeta.type === "randomDraw") {
                fallbackDetails.drawSource = storeMeta.drawSource || "food";
                fallbackDetails.loseEnabled = storeMeta.loseEnabled === true;
                fallbackDetails.losePercent = Number(storeMeta.losePercent) || 0;
                fallbackDetails.drawCandidates = Array.isArray(
                  storeMeta.drawCandidates,
                )
                  ? storeMeta.drawCandidates
                  : [];
              }
              await addItemToInventory(
                result.winnerId,
                fallbackItemId,
                1,
                fallbackDetails,
              );
            }
            alert(
              `ΏθΟΚ ΈςσΊΣε ΈΜυΉΕ▒! ${result.winnerName}ΈΜαΉζ┤ ΉΧΕΉζ┤ΊΖεΉζΕ Έ░δΉΧαΉΛ╡ΈΜΙΈΜν.\n(ΉΕεΈ▓Ε Ή▓αΈου Ήζ╝Έ╢Α ΉΜνΊΝρ - Ά┤ΑΈουΉηΡΉΩΡΆ▓Ν Έυ╕Ήζα)`,
            );
          } catch (fallbackErr) {
            logger.error("ΊΠ┤Έ░▒ Ήζ╕Έ▓νΊΗιΈου ΉπΑΆ╕Κ ΉΜνΊΝρ:", fallbackErr);
            alert(
              "ΈςσΊΣεΈΛΦ ΈΜυΉΕ▒ΊΨΙΉπΑΈπΝ ΉΧΕΉζ┤ΊΖε ΉπΑΆ╕Κ ΉνΣ ΉανΈξαΆ░Α Έ░εΉΔζΊΨΙΉΛ╡ΈΜΙΈΜν. Ά┤ΑΈουΉηΡΉΩΡΆ▓Ν Έυ╕ΉζαΊΧαΉΕ╕ΉγΦ.",
            );
          }
        }
      }

      setContributeModal(null);
      setContributeAmount("");
      fetchCampaigns();
    } catch (err) {
      // ΊΛ╕ΈηεΉηφΉΖα Ή╗νΈ░Μ ΉιΕ ΉΜνΊΝρΈπΝ ΈκνΈ░▒ (Ή╗νΈ░Μ ΊδΕ ΊδΕΉ▓αΈου ΉανΈξαΈΛΦ cash Έυ┤Ά┤Α)
      if (!transactionCommitted && optimisticUpdate) {
        optimisticUpdate({ cash: finalAmount });
      }
      logger.error("ΈςρΆ╕Ι Ή░╕ΉΩυ ΉΜνΊΝρ:", err);
      alert(err.message || "Ή░╕ΉΩυΉΩΡ ΉΜνΊΝρΊΨΙΉΛ╡ΈΜΙΈΜν.");
    } finally {
      setIsContributing(false);
    }
  };

  // Ή║ιΊΟαΉζ╕ ΉΓφΉιε (Ά┤ΑΈουΉηΡ ΈαΡΈΛΦ ΉΔζΉΕ▒ΉηΡ)
  const handleDelete = async (campaign) => {
    if (
      !window.confirm(
        "ΉιΧΈπΡ ΉΓφΉιεΊΧαΉΜεΆ▓ιΉΛ╡ΈΜΙΆ╣Ν? ΈςρΆ╕ΙΈΡε Ά╕ΙΉΧκΉζΑ Ή░╕ΉΩυΉηΡΉΩΡΆ▓Ν ΊβαΈ╢ΙΈΡσΈΜΙΈΜν.",
      )
    )
      return;

    try {
      // ΊβαΈ╢Ι Ή▓αΈου
      if (campaign.contributors?.length > 0 && campaign.currentAmount > 0) {
        for (const contributor of campaign.contributors) {
          const userRef = doc(db, "users", contributor.userId);
          await runTransaction(db, async (transaction) => {
            const snap = await transaction.get(userRef);
            if (snap.exists()) {
              transaction.update(userRef, {
                cash: (snap.data().cash || 0) + contributor.amount,
              });
            }
          });
        }
      }
      await deleteDoc(doc(db, "groupPurchases", campaign.id));
      fetchCampaigns();
    } catch (err) {
      logger.error("ΊΧρΆ╗αΆ╡υΈπν ΉΓφΉιε ΉΜνΊΝρ:", err);
      alert("ΉΓφΉιεΉΩΡ ΉΜνΊΝρΊΨΙΉΛ╡ΈΜΙΈΜν.");
    }
  };

  // ΊΧΕΊΕ░ΈΡε Ή║ιΊΟαΉζ╕
  const filtered = enrichedCampaigns.filter((c) => {
    if (filter === "active") return c.status === "active";
    if (filter === "completed") return c.status === "completed";
    return true;
  });

  // ΉπΕΊΨΚΈξι Ά│ΕΉΓ░
  const getProgress = (c) =>
    Math.min(100, Math.round((c.currentAmount / c.targetPrice) * 100));

  // ΈΓ┤ Ά╕░ΉΩυΆ╕Ι
  const getMyContribution = (c) => {
    const me = c.contributors?.find((x) => x.userId === user?.uid);
    return me?.amount || 0;
  };

  // ΉΔΒΉιΡ ΉΧΕΉζ┤ΊΖε ΉΕιΊΔζ ΉΜε ΊΠ╝ ΉηΡΈΠβ Ή▒ΕΉγ░Ά╕░
  const handleSelectStoreItem = (itemId) => {
    const item = items?.find((i) => i.id === itemId);
    if (item) {
      setNewCampaign((prev) => ({
        ...prev,
        selectedItemId: itemId,
        itemName: item.name,
        itemIcon: item.icon || "ΏθΟΒ",
        itemDescription: item.description || "",
        targetPrice: String(item.price || ""),
      }));
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="w-8 h-8 border-2 border-cyber-cyan border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="w-full px-4 md:px-6 lg:px-8 py-6 space-y-6">
      {/* ΊΩνΈΞΦ */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-purple-500/20 to-indigo-500/20 border border-purple-500/30 flex items-center justify-center">
            <Users className="w-5 h-5 text-purple-400" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 font-jua">ΊΧρΆ╗αΆ╡υΈπν</h1>
            <p className="text-xs text-slate-500">
              Ή╣εΆ╡υΈΥνΆ│╝ ΈςρΆ╕ΙΊΧαΆ│ι, Ή╡εΈΜν Ά╕░ΉΩυΉηΡΆ░Α ΉΧΕΉζ┤ΊΖεΉζΕ ΊγΞΈΥζΊΧ┤ΉγΦ!
            </p>
          </div>
        </div>
        <button
          onClick={() => setShowCreateModal(true)}
          className="flex items-center gap-2 px-4 py-2 rounded-xl bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 text-white text-sm font-bold transition-all hover:scale-105 shadow-lg shadow-purple-500/20"
        >
          <Plus className="w-4 h-4" />ΉΔΙ ΊΧρΆ╗αΆ╡υΈπν
        </button>
      </div>

      {/* ΊΧΕΊΕ░ ΊΔφ */}
      <div className="flex gap-2">
        {[
          { key: "active", label: "ΉπΕΊΨΚΉνΣ", icon: Clock },
          { key: "completed", label: "ΉβΕΈμΝ", icon: Trophy },
          { key: "all", label: "ΉιΕΉ▓┤", icon: Users },
        ].map(({ key, label, icon: Icon }) => (
          <button
            key={key}
            onClick={() => setFilter(key)}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
              filter === key
                ? "bg-purple-500/20 text-purple-600 border border-purple-500/30"
                : "bg-slate-100 text-slate-500 border border-transparent hover:bg-slate-200"
            }`}
          >
            <Icon className="w-3.5 h-3.5" />
            {label}
          </button>
        ))}
      </div>

      {/* Ή║ιΊΟαΉζ╕ ΈςσΈκζ */}
      {filtered.length === 0 ? (
        <div className="text-center py-16">
          <div className="text-5xl mb-4 opacity-50">Ώθνζ</div>
          <p className="text-slate-500 text-lg font-medium">
            {filter === "active"
              ? "ΉπΕΊΨΚ ΉνΣΉζ╕ ΊΧρΆ╗αΆ╡υΈπνΆ░Α ΉΩΗΉΛ╡ΈΜΙΈΜν"
              : filter === "completed"
                ? "ΉβΕΈμΝΈΡε ΊΧρΆ╗αΆ╡υΈπνΆ░Α ΉΩΗΉΛ╡ΈΜΙΈΜν"
                : "ΊΧρΆ╗αΆ╡υΈπν ΈΓ┤ΉΩφΉζ┤ ΉΩΗΉΛ╡ΈΜΙΈΜν"}
          </p>
          <p className="text-gray-500 text-sm mt-1">
            ΉΔΙ ΊΧρΆ╗αΆ╡υΈπνΈξ╝ ΉΜεΉηΣΊΧ┤Έ│┤ΉΕ╕ΉγΦ!
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map((campaign) => {
            const progress = getProgress(campaign);
            const myAmount = getMyContribution(campaign);
            const isCompleted = campaign.status === "completed";
            const isExpanded = expandedId === campaign.id;
            const canDelete = isAdmin() || campaign.initiatorId === user?.uid;
            const remaining = campaign.targetPrice - campaign.currentAmount;

            return (
              <div
                key={campaign.id}
                className={`rounded-2xl border transition-all ${
                  isCompleted
                    ? "bg-gradient-to-r from-emerald-50 to-teal-50 border-emerald-300"
                    : "bg-white border-slate-200 hover:border-purple-500/30"
                }`}
              >
                {/* ΈσΦΉζ╕ Ή╣┤ΈΥε */}
                <div className="p-4">
                  <div className="flex items-start gap-3">
                    {/* ΉΧΕΉζ┤Ή╜α */}
                    <div
                      className={`w-12 h-12 rounded-xl flex items-center justify-center text-2xl flex-shrink-0 ${
                        isCompleted
                          ? "bg-emerald-500/20"
                          : "bg-purple-500/10 border border-purple-500/20"
                      }`}
                    >
                      {campaign.itemIcon}
                    </div>

                    {/* ΈΓ┤Ήγσ */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="text-base font-bold text-slate-800 truncate">
                          {campaign.itemName}
                        </h3>
                        {isCompleted && (
                          <span className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-emerald-500/20 text-emerald-600 text-xs font-bold">
                            <Trophy className="w-3 h-3" />
                            ΈΜυΉΕ▒
                          </span>
                        )}
                        {isCompleted && campaign.winnerName && (
                          <span className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-amber-500/20 text-amber-600 text-xs font-bold">
                            ΏθΠΗ {campaign.winnerName}
                          </span>
                        )}
                      </div>

                      {campaign.itemDescription && (
                        <p className="text-xs text-slate-500 mb-2 line-clamp-1">
                          {campaign.itemDescription}
                        </p>
                      )}

                      {/* ΉπΕΊΨΚ Έ░Φ */}
                      <div className="relative h-3 bg-slate-100 rounded-full overflow-hidden mb-2">
                        <div
                          className={`absolute inset-y-0 left-0 rounded-full transition-all duration-500 ${
                            isCompleted
                              ? "bg-gradient-to-r from-emerald-500 to-teal-400"
                              : "bg-gradient-to-r from-purple-500 to-indigo-500"
                          }`}
                          style={{ width: `${progress}%` }}
                        />
                        <div className="absolute inset-0 flex items-center justify-center">
                          <span className="text-[10px] font-bold text-slate-800">
                            {progress}%
                          </span>
                        </div>
                      </div>

                      {/* Ά╕ΙΉΧκ ΉιΧΈ│┤ */}
                      <div className="flex items-center justify-between text-xs">
                        <span className="text-slate-500">
                          {formatKoreanNumber(campaign.currentAmount)}
                          {currencyUnit} /{" "}
                          {formatKoreanNumber(campaign.targetPrice)}
                          {currencyUnit}
                        </span>
                        <span className="text-gray-500">
                          Ή░╕ΉΩυ {campaign.contributors?.length || 0}ΈςΖ
                        </span>
                      </div>

                      {/* ΈΓ┤ Ά╕░ΉΩυ */}
                      {myAmount > 0 && (
                        <div className="mt-1.5 text-xs text-purple-600">
                          ΈΓ┤ Ά╕░ΉΩυ: {formatKoreanNumber(myAmount)}
                          {currencyUnit}
                        </div>
                      )}
                    </div>

                    {/* Ή░╕ΉΩυ/ΉΔΒΉΕ╕ Έ▓ΕΊΛ╝ */}
                    <div className="flex flex-col gap-1.5 flex-shrink-0">
                      {!isCompleted && (
                        <button
                          onClick={() => {
                            setContributeModal(campaign);
                            setContributeAmount("");
                          }}
                          className="flex items-center gap-1.5 px-3 py-2 rounded-lg bg-purple-600/80 hover:bg-purple-500 text-white text-xs font-bold transition-all"
                        >
                          <HandCoins className="w-3.5 h-3.5" />
                          Ή░╕ΉΩυ
                        </button>
                      )}
                      <button
                        onClick={() =>
                          setExpandedId(isExpanded ? null : campaign.id)
                        }
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-slate-100 hover:bg-slate-200 text-slate-500 text-xs transition-all"
                      >
                        {isExpanded ? (
                          <ChevronUp className="w-3.5 h-3.5" />
                        ) : (
                          <ChevronDown className="w-3.5 h-3.5" />
                        )}
                        ΉΔΒΉΕ╕
                      </button>
                    </div>
                  </div>
                </div>

                {/* ΉΔΒΉΕ╕ ΊΝρΈΕΡ */}
                {isExpanded && (
                  <div className="px-4 pb-4 border-t border-slate-200 pt-3 space-y-3">
                    <div className="text-xs text-gray-500">
                      ΉΜεΉηΣ: {campaign.initiatorName} ┬╖{" "}
                      {campaign.createdAt?.toDate
                        ? campaign.createdAt
                            .toDate()
                            .toLocaleDateString("ko-KR")
                        : ""}
                    </div>

                    {/* ΈΜ╣Ή▓ρΉηΡ ΉΧΙΈΓ┤ */}
                    {isCompleted && campaign.winnerName && (
                      <div className="flex items-center gap-2 bg-amber-500/10 border border-amber-500/20 rounded-lg px-3 py-2.5">
                        <span className="text-lg">ΏθΠΗ</span>
                        <div>
                          <p className="text-sm font-bold text-amber-600">
                            ΉΧΕΉζ┤ΊΖε ΊγΞΈΥζ: {campaign.winnerName}
                          </p>
                          <p className="text-xs text-amber-600">
                            Ή╡εΈΜν Ά╕░ΉΩυΉηΡΉΩΡΆ▓Ν ΉΧΕΉζ┤ΊΖεΉζ┤ ΉπΑΆ╕ΚΈΡαΉΩΙΉΛ╡ΈΜΙΈΜν
                          </p>
                        </div>
                      </div>
                    )}

                    {/* Ή░╕ΉΩυΉηΡ ΈςσΈκζ */}
                    {campaign.contributors?.length > 0 && (
                      <div>
                        <p className="text-xs font-bold text-slate-600 mb-2">
                          Ή░╕ΉΩυΉηΡ ({campaign.contributors.length}ΈςΖ)
                        </p>
                        <div className="space-y-1.5">
                          {[...campaign.contributors]
                            .sort((a, b) => {
                              if (b.amount !== a.amount)
                                return b.amount - a.amount;
                              const aT =
                                a.firstContributedAt || a.contributedAt;
                              const bT =
                                b.firstContributedAt || b.contributedAt;
                              const aMs =
                                aT?.toMillis?.() || aT?.getTime?.() || 0;
                              const bMs =
                                bT?.toMillis?.() || bT?.getTime?.() || 0;
                              return aMs - bMs;
                            })
                            .map((c, i) => {
                              const isWinner = campaign.winnerId === c.userId;
                              return (
                                <div
                                  key={i}
                                  className={`flex items-center justify-between rounded-lg px-3 py-2 ${isWinner ? "bg-amber-500/10 border border-amber-500/20" : "bg-slate-100"}`}
                                >
                                  <div className="flex items-center gap-2">
                                    <span className="text-xs font-bold text-slate-600">
                                      {i === 0
                                        ? "ΏθξΘ"
                                        : i === 1
                                          ? "ΏθξΙ"
                                          : i === 2
                                            ? "ΏθξΚ"
                                            : `${i + 1}.`}
                                    </span>
                                    <span
                                      className={`text-sm ${isWinner ? "text-amber-600 font-bold" : "text-slate-800"}`}
                                    >
                                      {c.userName}
                                    </span>
                                  </div>
                                  <span
                                    className={`text-sm font-bold ${isWinner ? "text-amber-600" : "text-purple-600"}`}
                                  >
                                    {formatKoreanNumber(c.amount)}
                                    {currencyUnit}
                                  </span>
                                </div>
                              );
                            })}
                        </div>
                      </div>
                    )}

                    {/* ΈΓρΉζΑ Ά╕ΙΉΧκ */}
                    {!isCompleted && remaining > 0 && (
                      <div className="flex items-center gap-2 bg-amber-500/10 border border-amber-500/20 rounded-lg px-3 py-2">
                        <AlertCircle className="w-4 h-4 text-amber-600 flex-shrink-0" />
                        <span className="text-xs text-amber-600">
                          ΈςσΊΣεΆ╣ΝΉπΑ{" "}
                          <strong>
                            {formatKoreanNumber(remaining)}
                            {currencyUnit}
                          </strong>{" "}
                          ΈΞΦ ΊΧΕΉγΦΊΧσΈΜΙΈΜν
                        </span>
                      </div>
                    )}

                    {/* ΉΓφΉιε Έ▓ΕΊΛ╝ */}
                    {canDelete && (
                      <button
                        onClick={() => handleDelete(campaign)}
                        className="flex items-center gap-1.5 px-3 py-2 rounded-lg bg-red-500/10 hover:bg-red-500/20 text-red-600 text-xs font-medium transition-all"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                        ΉΓφΉιε (ΊβαΈ╢Ι Ή▓αΈου)
                      </button>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* ========== ΉΔΙ Ή║ιΊΟαΉζ╕ ΉΔζΉΕ▒ ΈςρΈΜυ ========== */}
      {showCreateModal && (
        <div
          className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/70 backdrop-blur-sm p-4"
          onClick={() => setShowCreateModal(false)}
        >
          <div
            className="w-full max-w-md bg-white border border-purple-500/30 rounded-2xl shadow-2xl overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            {/* ΈςρΈΜυ ΊΩνΈΞΦ */}
            <div className="flex items-center justify-between px-5 py-4 bg-gradient-to-r from-purple-600/20 to-indigo-600/20 border-b border-purple-500/20">
              <h2 className="text-lg font-bold text-slate-800 font-jua flex items-center gap-2">
                <Plus className="w-5 h-5 text-purple-400" />ΉΔΙ ΊΧρΆ╗αΆ╡υΈπν
              </h2>
              <button
                onClick={() => setShowCreateModal(false)}
                className="p-1 rounded-lg hover:bg-slate-100 text-slate-500 hover:text-slate-700 transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-5 space-y-4">
              {/* ΉΔΒΉιΡ ΉΧΕΉζ┤ΊΖε ΉΕιΊΔζ (ΊΧΕΉΙα) */}
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1.5">
                  ΉΧΕΉζ┤ΊΖε ΉΕιΊΔζ *
                </label>
                <select
                  value={newCampaign.selectedItemId}
                  onChange={(e) => handleSelectStoreItem(e.target.value)}
                  className="w-full px-3 py-2.5 rounded-xl bg-white border border-slate-200 text-slate-800 text-sm focus:border-purple-500/50 focus:outline-none [&>option]:bg-white [&>option]:text-slate-800"
                >
                  <option value="">-- ΉΧΕΉζ┤ΊΖεΉζΕ ΉΕιΊΔζΊΧαΉΕ╕ΉγΦ --</option>
                  {(items || [])
                    .filter((i) => i.available !== false)
                    .map((i) => (
                      <option key={i.id} value={i.id}>
                        {i.icon || "ΏθΟΒ"} {i.name} -{" "}
                        {formatKoreanNumber(i.price)}
                        {currencyUnit}
                      </option>
                    ))}
                </select>
              </div>

              {/* ΉΕιΊΔζΈΡε ΉΧΕΉζ┤ΊΖε Έψ╕ΈουΈ│┤Ά╕░ */}
              {newCampaign.selectedItemId && (
                <div className="flex items-center gap-3 bg-purple-500/10 border border-purple-500/20 rounded-xl p-3">
                  <span className="text-2xl">{newCampaign.itemIcon}</span>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-bold text-slate-800">
                      {newCampaign.itemName}
                    </p>
                    {newCampaign.itemDescription && (
                      <p className="text-xs text-slate-500 truncate">
                        {newCampaign.itemDescription}
                      </p>
                    )}
                    <p className="text-xs text-purple-600 font-bold mt-0.5">
                      ΈςσΊΣε: {formatKoreanNumber(newCampaign.targetPrice)}
                      {currencyUnit}
                    </p>
                  </div>
                </div>
              )}

              {/* ΈςσΊΣε Ά╕ΙΉΧκ (ΉΔΒΉιΡ Ά░ΑΆ▓σΉε╝Έκε ΉηΡΈΠβ Ά│ιΉιΧ) */}
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1.5">
                  ΈςσΊΣε Ά╕ΙΉΧκ (ΉΔΒΉιΡ ΊαΕΉηυ Ά░ΑΆ▓σ ΉηΡΈΠβ ΉιΒΉγσ)
                </label>
                <div className="w-full px-3 py-2.5 rounded-xl bg-slate-50 border border-slate-200 text-slate-800 text-sm font-bold">
                  {newCampaign.selectedItemId
                    ? `${formatKoreanNumber(newCampaign.targetPrice)}${currencyUnit}`
                    : "ΉΧΕΉζ┤ΊΖεΉζΕ Έρ╝ΉιΑ ΉΕιΊΔζΊΧαΉΕ╕ΉγΦ"}
                </div>
                <p className="text-[11px] text-slate-400 mt-1">
                  ΏθΤκ ΊΤΙΉιΙ ΉΜε ΉηΡΈΠβ Ά░ΑΆ▓σ ΉΔΒΉΛ╣Ήζ┤ ΊΧρΆ╗αΆ╡υΈπνΉΩΡΈΠΕ ΉιΒΉγσΈΡσΈΜΙΈΜν.
                  ΊΧε ΉΧΕΉζ┤ΊΖεΉζΑ ΊΧε Έ▓ΙΉΩΡ ΊΧε Ά▒┤ΈπΝ ΉπΕΊΨΚ Ά░ΑΈΛξΊΧσΈΜΙΈΜν.
                </p>
              </div>

              {/* ΉΔζΉΕ▒ Έ▓ΕΊΛ╝ */}
              <button
                onClick={handleCreate}
                disabled={
                  !newCampaign.selectedItemId ||
                  !newCampaign.targetPrice ||
                  parseInt(newCampaign.targetPrice) <= 0
                }
                className="w-full py-3 rounded-xl bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 disabled:from-gray-600 disabled:to-gray-700 disabled:cursor-not-allowed text-white font-bold text-sm transition-all"
              >
                ΊΧρΆ╗αΆ╡υΈπν ΉΜεΉηΣΊΧαΆ╕░
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ========== ΈςρΆ╕Ι Ή░╕ΉΩυ ΈςρΈΜυ ========== */}
      {contributeModal && (
        <div
          className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/70 backdrop-blur-sm p-4"
          onClick={() => setContributeModal(null)}
        >
          <div
            className="w-full max-w-sm bg-white border border-purple-500/30 rounded-2xl shadow-2xl overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="px-5 py-4 bg-gradient-to-r from-purple-600/20 to-indigo-600/20 border-b border-purple-500/20">
              <h2 className="text-lg font-bold text-slate-800 font-jua flex items-center gap-2">
                <HandCoins className="w-5 h-5 text-purple-400" />
                ΈςρΆ╕Ι Ή░╕ΉΩυ
              </h2>
            </div>

            <div className="p-5 space-y-4">
              {/* Ή║ιΊΟαΉζ╕ ΉιΧΈ│┤ */}
              <div className="flex items-center gap-3 bg-slate-100 rounded-xl p-3">
                <span className="text-2xl">{contributeModal.itemIcon}</span>
                <div>
                  <p className="text-sm font-bold text-slate-800">
                    {contributeModal.itemName}
                  </p>
                  <p className="text-xs text-slate-500">
                    ΈΓρΉζΑ Ά╕ΙΉΧκ:{" "}
                    {formatKoreanNumber(
                      contributeModal.targetPrice -
                        contributeModal.currentAmount,
                    )}
                    {currencyUnit}
                  </p>
                </div>
              </div>

              {/* ΈΓ┤ ΉηΦΉΧκ */}
              <div className="text-xs text-slate-500">
                ΈΓ┤ ΉηΦΉΧκ:{" "}
                <span className="text-slate-800 font-bold">
                  {formatKoreanNumber(userDoc?.cash || 0)}
                  {currencyUnit}
                </span>
              </div>

              {/* Ά╕ΙΉΧκ ΉηΖΈιξ */}
              <div className="relative">
                <input
                  type="number"
                  value={contributeAmount}
                  onChange={(e) => setContributeAmount(e.target.value)}
                  className="w-full px-3 py-3 pr-14 rounded-xl bg-white border border-slate-200 text-slate-800 text-lg font-bold focus:border-purple-500/50 focus:outline-none text-center"
                  placeholder="0"
                  min="1"
                  max={Math.min(
                    userDoc?.cash || 0,
                    contributeModal.targetPrice - contributeModal.currentAmount,
                  )}
                  autoFocus
                />
                <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-gray-500">
                  {currencyUnit}
                </span>
              </div>

              {/* Έ╣ιΈξ╕ Ά╕ΙΉΧκ Έ▓ΕΊΛ╝ */}
              <div className="flex gap-2">
                {[100, 500, 1000, 5000].map((amt) => (
                  <button
                    key={amt}
                    onClick={() => setContributeAmount(String(amt))}
                    className="flex-1 py-1.5 rounded-lg bg-slate-100 hover:bg-purple-500/20 text-slate-600 text-xs font-medium transition-all"
                  >
                    {formatKoreanNumber(amt)}
                  </button>
                ))}
              </div>

              {/* ΉιΕΉΧκ ΊΙυΉηΖ */}
              <button
                onClick={() => {
                  const max = Math.min(
                    userDoc?.cash || 0,
                    contributeModal.targetPrice - contributeModal.currentAmount,
                  );
                  setContributeAmount(String(max));
                }}
                className="w-full py-2 rounded-lg bg-slate-100 hover:bg-slate-200 text-slate-600 text-xs font-medium transition-all"
              >
                ΈΓρΉζΑ Ά╕ΙΉΧκ ΉιΕΈ╢Α Ή░╕ΉΩυ
              </button>

              {/* Ή░╕ΉΩυ Έ▓ΕΊΛ╝ */}
              <div className="flex gap-2">
                <button
                  onClick={() => setContributeModal(null)}
                  className="flex-1 py-3 rounded-xl bg-slate-100 hover:bg-slate-200 text-slate-500 font-bold text-sm transition-all"
                >
                  Ή╖ρΉΗΝ
                </button>
                <button
                  onClick={handleContribute}
                  disabled={
                    isContributing ||
                    !contributeAmount ||
                    parseInt(contributeAmount) <= 0 ||
                    parseInt(contributeAmount) > (userDoc?.cash || 0)
                  }
                  className="flex-1 py-3 rounded-xl bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 disabled:from-gray-600 disabled:to-gray-700 disabled:cursor-not-allowed text-white font-bold text-sm transition-all"
                >
                  {isContributing ? "Ή▓αΈου ΉνΣ..." : "Ή░╕ΉΩυΊΧαΆ╕░"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
